import { describe, it, expect } from 'vitest';
import type { User } from '../../src/models/user.js';
import {
  validateUserExists,
  validateEmailNotTaken,
  validateEmailNotInUse,
} from '../../src/validators/user.validator.js';

const mockUser: User = {
  id: 'user-0001',
  name: 'Alice',
  email: 'alice@example.com',
  role: 'member',
  createdAt: new Date(),
  updatedAt: new Date(),
};

describe('user.validator', () => {
  describe('validateUserExists', () => {
    it('should not throw when user exists', () => {
      expect(() => validateUserExists(mockUser, 'user-0001')).not.toThrow();
    });

    it('should throw when user is undefined', () => {
      expect(() => validateUserExists(undefined, 'user-9999')).toThrow(
        'User not found: user-9999',
      );
    });
  });

  describe('validateEmailNotTaken', () => {
    it('should not throw when no existing user', () => {
      expect(() =>
        validateEmailNotTaken(undefined, 'new@example.com'),
      ).not.toThrow();
    });

    it('should throw when email is already taken', () => {
      expect(() =>
        validateEmailNotTaken(mockUser, 'alice@example.com'),
      ).toThrow('User with email alice@example.com already exists');
    });
  });

  describe('validateEmailNotInUse', () => {
    it('should not throw when no existing user', () => {
      expect(() =>
        validateEmailNotInUse(undefined, 'new@example.com'),
      ).not.toThrow();
    });

    it('should throw when email is in use', () => {
      expect(() =>
        validateEmailNotInUse(mockUser, 'alice@example.com'),
      ).toThrow('Email alice@example.com is already in use');
    });
  });
});

import { describe, it, expect } from 'vitest';
import type { Order, OrderStatus } from '../../src/models/order.js';
import {
  validateOrderExists,
  validateOrderHasItems,
  isValidStatusTransition,
  validateStatusTransition,
} from '../../src/validators/order.validator.js';

const mockOrder: Order = {
  id: 'order-0001',
  userId: 'user-0001',
  items: [{ productId: 'p1', name: 'Widget', quantity: 2, unitPrice: 10 }],
  total: 20,
  status: 'pending',
  createdAt: new Date(),
  updatedAt: new Date(),
};

describe('order.validator', () => {
  describe('validateOrderExists', () => {
    it('should not throw when order exists', () => {
      expect(() => validateOrderExists(mockOrder, 'order-0001')).not.toThrow();
    });

    it('should throw when order is undefined', () => {
      expect(() => validateOrderExists(undefined, 'order-9999')).toThrow(
        'Order not found: order-9999',
      );
    });
  });

  describe('validateOrderHasItems', () => {
    it('should not throw when items are present', () => {
      expect(() =>
        validateOrderHasItems([
          { productId: 'p1', name: 'Widget', quantity: 1, unitPrice: 10 },
        ]),
      ).not.toThrow();
    });

    it('should throw when items array is empty', () => {
      expect(() => validateOrderHasItems([])).toThrow(
        'Order must have at least one item',
      );
    });
  });

  describe('isValidStatusTransition', () => {
    const validTransitions: [OrderStatus, OrderStatus][] = [
      ['pending', 'confirmed'],
      ['pending', 'cancelled'],
      ['confirmed', 'shipped'],
      ['confirmed', 'cancelled'],
      ['shipped', 'delivered'],
    ];

    const invalidTransitions: [OrderStatus, OrderStatus][] = [
      ['pending', 'shipped'],
      ['pending', 'delivered'],
      ['confirmed', 'pending'],
      ['confirmed', 'delivered'],
      ['shipped', 'pending'],
      ['shipped', 'cancelled'],
      ['delivered', 'pending'],
      ['delivered', 'cancelled'],
      ['cancelled', 'pending'],
      ['cancelled', 'confirmed'],
    ];

    it.each(validTransitions)(
      'should return true for %s -> %s',
      (from, to) => {
        expect(isValidStatusTransition(from, to)).toBe(true);
      },
    );

    it.each(invalidTransitions)(
      'should return false for %s -> %s',
      (from, to) => {
        expect(isValidStatusTransition(from, to)).toBe(false);
      },
    );
  });

  describe('validateStatusTransition', () => {
    it('should not throw for valid transition', () => {
      expect(() => validateStatusTransition('pending', 'confirmed')).not.toThrow();
    });

    it('should throw for invalid transition', () => {
      expect(() => validateStatusTransition('pending', 'delivered')).toThrow(
        'Invalid status transition: pending -> delivered',
      );
    });

    it('should throw for transition from terminal state', () => {
      expect(() => validateStatusTransition('cancelled', 'confirmed')).toThrow(
        'Invalid status transition: cancelled -> confirmed',
      );
    });
  });
});

